/**
 * Loads privantix_site/products.json, fetches latest GitHub Release per repo from the API,
 * and renders cards into #product-cards-root.
 *
 * API: GET https://api.github.com/repos/{owner}/{repo}/releases/latest
 * Fallback: data/releases-cache.json (optional, generated by scripts/sync_releases_cache.py)
 */
(function () {
  const root = document.getElementById('product-cards-root');
  const errEl = document.getElementById('product-cards-error');
  if (!root) return;

  const GH_ACCEPT = 'application/vnd.github+json';

  function esc(s) {
    if (s == null) return '';
    const d = document.createElement('div');
    d.textContent = s;
    return d.innerHTML;
  }

  function parseRepo(full) {
    if (!full || typeof full !== 'string' || full.indexOf('/') === -1) return null;
    const i = full.indexOf('/');
    return { owner: full.slice(0, i), repo: full.slice(i + 1) };
  }

  function formatDate(iso) {
    if (!iso) return '—';
    try {
      const d = new Date(iso);
      return d.toLocaleDateString('es-ES', {
        year: 'numeric',
        month: 'short',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
      });
    } catch (e) {
      return iso;
    }
  }

  function sumDownloads(assets) {
    if (!assets || !assets.length) return 0;
    return assets.reduce(function (n, a) {
      return n + (typeof a.download_count === 'number' ? a.download_count : 0);
    }, 0);
  }

  function fetchLatestRelease(owner, repo) {
    const url =
      'https://api.github.com/repos/' + encodeURIComponent(owner) + '/' + encodeURIComponent(repo) + '/releases/latest';
    return fetch(url, {
      headers: { Accept: GH_ACCEPT },
      cache: 'no-store',
    }).then(function (r) {
      if (r.status === 404) return { _notFound: true };
      if (!r.ok) return { _error: true, status: r.status };
      return r.json();
    });
  }

  function loadCache() {
    return fetch('data/releases-cache.json', { cache: 'no-store' })
      .then(function (r) {
        return r.ok ? r.json() : null;
      })
      .catch(function () {
        return null;
      });
  }

  function releaseFromCache(cache, owner, repo) {
    if (!cache || !cache.repos) return null;
    const key = owner + '/' + repo;
    const entry = cache.repos[key];
    return entry && !entry.error ? entry.release : null;
  }

  Promise.all([fetch('products.json', { cache: 'no-store' }).then(function (r) {
    if (!r.ok) throw new Error('No se pudo cargar products.json (' + r.status + ')');
    return r.json();
  }), loadCache()])
    .then(function (tuple) {
      const data = tuple[0];
      const cache = tuple[1];
      const list = Array.isArray(data) ? data : data.products;
      if (!list || !list.length) throw new Error('products.json vacío o formato inválido');

      const uniqueKeys = [];
      const seen = {};
      list.forEach(function (p) {
        const pr = parseRepo(p.repo);
        if (!pr) return;
        const k = pr.owner + '/' + pr.repo;
        if (!seen[k]) {
          seen[k] = true;
          uniqueKeys.push(pr);
        }
      });

      const releaseMap = {};

      return Promise.all(
        uniqueKeys.map(function (pr) {
          const k = pr.owner + '/' + pr.repo;
          return fetchLatestRelease(pr.owner, pr.repo).then(function (rel) {
            if (rel && rel._notFound) {
              releaseMap[k] = releaseFromCache(cache, pr.owner, pr.repo) || { _notFound: true };
              return;
            }
            if (rel && rel._error) {
              releaseMap[k] = releaseFromCache(cache, pr.owner, pr.repo) || rel;
              return;
            }
            releaseMap[k] = rel;
          });
        })
      ).then(function () {
        return { list: list, releaseMap: releaseMap, usedCache: cache };
      });
    })
    .then(function (ctx) {
      const list = ctx.list;
      const releaseMap = ctx.releaseMap;

      root.innerHTML = list
        .map(function (p) {
          const pr = parseRepo(p.repo);
          const repoUrl = pr ? 'https://github.com/' + pr.owner + '/' + pr.repo : '';
          const key = pr ? pr.owner + '/' + pr.repo : '';
          const rel = key ? releaseMap[key] : null;

          var versionHtml = '<span class="badge rounded-pill badge-soft">—</span>';
          var metaHtml = '';
          var assetsHtml = '';
          var notesHtml = '';

          if (rel && rel._error) {
            versionHtml =
              '<span class="badge rounded-pill bg-warning text-dark" title="API GitHub">Error API</span>';
            metaHtml =
              '<p class="small text-warning mb-2">No se pudo obtener el release (HTTP ' +
              esc(rel.status) +
              '). ¿Límite de tasa? Vuelve a intentar o usa <code>scripts/sync_releases_cache.py</code>.</p>';
          } else if (rel && rel._notFound) {
            versionHtml = '<span class="badge rounded-pill badge-soft">Sin release</span>';
            metaHtml =
              '<p class="small mb-2" style="color: var(--px-muted);">Aún no hay release publicado en este repositorio.</p>';
          } else if (rel && rel.tag_name) {
            versionHtml =
              '<span class="badge rounded-pill badge-soft">' + esc(rel.tag_name) + '</span>';
            var totalDl = sumDownloads(rel.assets);
            metaHtml =
              '<ul class="small mb-2 ps-3" style="color: var(--px-muted);">' +
              '<li><strong>Versión:</strong> ' +
              esc(rel.name || rel.tag_name) +
              '</li>' +
              '<li><strong>Publicado:</strong> ' +
              esc(formatDate(rel.published_at)) +
              '</li>' +
              '<li><strong>Descargas (activos):</strong> ' +
              (totalDl >= 0 ? String(totalDl) : '—') +
              '</li>' +
              '</ul>';

            if (rel.assets && rel.assets.length) {
              assetsHtml = rel.assets
                .map(function (a) {
                  var dc =
                    typeof a.download_count === 'number' ? ' · ' + a.download_count + ' ↓' : '';
                  return (
                    '<a class="btn btn-sm btn-outline-privantix me-1 mb-1" href="' +
                    esc(a.browser_download_url) +
                    '" target="_blank" rel="noopener" download>' +
                    '<i class="bi bi-download me-1" aria-hidden="true"></i>' +
                    esc(a.name) +
                    esc(dc) +
                    '</a>'
                  );
                })
                .join('');
            } else {
              assetsHtml =
                '<p class="small mb-1" style="color: var(--px-muted);">Sin archivos adjuntos en el último release.</p>';
            }

            if (rel.html_url) {
              notesHtml =
                '<a class="btn btn-sm btn-outline-secondary me-1 mb-1" href="' +
                esc(rel.html_url) +
                '" target="_blank" rel="noopener">Notas de versión (GitHub)</a>';
            }
          } else {
            metaHtml =
              '<p class="small mb-2" style="color: var(--px-muted);">No hay datos de release.</p>';
          }

          var doc = p.documentation
            ? '<a class="btn btn-sm btn-privantix me-1 mb-1" href="' +
              esc(p.documentation) +
              '" target="_blank" rel="noopener">Documentación</a>'
            : '';
          var ch = p.changelog
            ? '<a class="btn btn-sm btn-outline-secondary me-1 mb-1" href="' +
              esc(p.changelog) +
              '" target="_blank" rel="noopener">Changelog</a>'
            : '';
          var rm = p.roadmap
            ? '<a class="btn btn-sm btn-outline-secondary me-1 mb-1" href="' +
              esc(p.roadmap) +
              '" target="_blank" rel="noopener">Roadmap</a>'
            : '';
          var repoBtn = repoUrl
            ? '<a class="btn btn-sm btn-outline-secondary me-1 mb-1" href="' +
              esc(repoUrl) +
              '" target="_blank" rel="noopener">Repositorio</a>'
            : '';

          return (
            '<div class="col-md-6 col-xl-4">' +
            '<div class="feature-card p-4 h-100 d-flex flex-column">' +
            '<div class="d-flex justify-content-between align-items-start gap-2">' +
            '<h5 class="mb-0">' +
            esc(p.name) +
            '</h5>' +
            versionHtml +
            '</div>' +
            '<p class="small mt-3 mb-2 flex-grow-1" style="color: var(--px-muted);">' +
            esc(p.description) +
            '</p>' +
            '<p class="small mb-1"><code>' +
            esc(p.repo || '') +
            '</code></p>' +
            metaHtml +
            '<div class="mt-auto pt-2">' +
            assetsHtml +
            '<div class="d-flex flex-wrap gap-0 mt-2">' +
            repoBtn +
            doc +
            ch +
            notesHtml +
            rm +
            '</div>' +
            '</div>' +
            '</div></div>'
          );
        })
        .join('');

      if (errEl) errEl.classList.add('d-none');
    })
    .catch(function (e) {
      if (errEl) {
        errEl.textContent = e.message || String(e);
        errEl.classList.remove('d-none');
      }
    });
})();
